const response = $input.first().json;
const statusCode = response.statusCode || 200;
const body = response.body;

if (statusCode >= 400) {
  return [{
    json: {
      success: false,
      error: `Supabase returned ${statusCode}`,
      details: body,
      tool: 'memory_deep_dive'
    }
  }];
}

let memoryContext = null;
try {
  if (typeof body === 'string') {
    memoryContext = JSON.parse(body);
  } else if (body && typeof body === 'object') {
    memoryContext = body;
  }
} catch (e) {
  memoryContext = null;
}

if (!memoryContext || !memoryContext.id) {
  return [{
    json: {
      success: false,
      error: 'Memory not found',
      tool: 'memory_deep_dive'
    }
  }];
}

const formatted = {
  memory: {
    id: memoryContext.id,
    title: memoryContext.title,
    summary: memoryContext.summary,
    transcript: memoryContext.transcript,
    source: memoryContext.source,
    created_at: memoryContext.created_at
  },
  reflections: memoryContext.reflections || [],
  decisions: memoryContext.decisions || [],
  tasks: memoryContext.tasks || [],
  entities: memoryContext.entities || [],
  strategic_insights: memoryContext.strategic_insights || []
};

return [{
  json: {
    success: true,
    memory_context: formatted,
    tool: 'memory_deep_dive',
    message: `Retrieved full context for memory: ${formatted.memory.title || 'Untitled'}`
  }
}];
